std::string markdownToHtml(const std::string& markdown) {
    std::stringstream sstream(markdown);
    std::string html;
    std::string line;
    std::smatch match;
    int index = 0;

    // Find all markdown lines and convert them to HTML
    while (std::getline(sstream, line)) {
        // Find the markdown syntax
        if (std::regex_search(line, match)) {
            html += "<p>";
            // Add the rest of the line to the HTML string
            html += line.substr(match[0].first, match[0].second);
            html += "</p>";
            // Skip the line
            index++;
        } else {
            // If no markdown syntax is found, add the line to the HTML string
            html += line + "<br>";
        }
    }

    return html;
}

